const BATCH = 200;

function parseMeta(raw) {
  if (!raw) return {};
  try {
    return typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch {
    return {};
  }
}

function isPending(row, headers) {
  const h = {};
  headers.forEach((key, i) => {
    if (key) h[key] = String(row[i] ?? '').trim();
  });

  const segment = (h.segment || '').toLowerCase();
  const status = (h.status || '').toLowerCase();
  const meta = parseMeta(h.meta);

  if (meta.classify_method === 'llm') return false;
  if (status === 'classified' && segment && segment !== 'unclassified') return false;

  const text = h.text || '';
  if (!text.trim()) return false;

  if (!segment || segment === 'unclassified') return true;
  if (status === 'review') return true;
  if (meta.needs_llm === true) return true;

  return false;
}

const res = $input.first().json;
const rows = Array.isArray(res.values) ? res.values : [];

if (rows.length < 2) {
  return [{ json: { empty: true, message: 'content_queue trống' } }];
}

const headers = rows[0].map((x) => String(x ?? '').trim().toLowerCase());
const out = [];

for (let i = 1; i < rows.length; i++) {
  const cells = rows[i];
  if (!cells?.some((c) => String(c ?? '').trim())) continue;
  if (!isPending(cells, headers)) continue;

  const row = { sheet_row: i + 1 };
  headers.forEach((key, j) => {
    if (key) row[key] = cells[j] ?? '';
  });
  out.push({ json: row });
  if (out.length >= BATCH) break;
}

if (!out.length) {
  return [{ json: { empty: true, message: 'Không còn dòng pending classify' } }];
}

return out;

const data = $getWorkflowStaticData('global');
data.a2_stats = { sheet_ok: 0, sheet_fail: 0, llm: 0, regex: 0, parse_fail: 0 };
return $input.all();

const RULES = [
  { segment: 'noxh_income', score: 80, interest_key: 'thu_nhap_noxh', patterns: [/thu nhập|lương|vay ngân hàng|vay mua nhà|noxh|nhà ở xã hội|nha o xa hoi|hồ sơ noxh|điều kiện mua noxh/i] },
  { segment: 'valuation', score: 70, interest_key: 'dinh_gia_tham_dinh', patterns: [/định giá|thẩm định|chứng thư|dinh gia|tham dinh/i] },
  { segment: 'sme_credit', score: 75, interest_key: 'room_tin_dung_sme', patterns: [/room tín dụng|room tin dung|doanh nghiệp|\bsme\b|vay doanh nghiệp/i] },
  { segment: 'general_inbound', score: 55, interest_key: 'quan_tam_bds', patterns: [/giá|\bcăn\b|m²|m2|block|dự án|du an|bds|bất động sản|bat dong san|mua nhà|mua nha/i] },
];

function classifyText(text) {
  const t = String(text || '').normalize('NFC').toLowerCase();
  let best = { segment: 'unclassified', score: 0, interest_key: 'unknown', matched: [] };
  for (const rule of RULES) {
    for (const re of rule.patterns) {
      if (re.test(t)) {
        if (rule.score > best.score) {
          best = { segment: rule.segment, score: rule.score, interest_key: rule.interest_key, matched: [re.source] };
        }
        break;
      }
    }
  }
  return best;
}

return $input.all().map((item) => {
  const j = item.json;
  const text = j.text ?? '';
  const result = classifyText(text);
  const needs_llm =
    (result.segment === 'unclassified' && String(text).trim().length > 0) ||
    (result.score >= 40 && result.score <= 59);

  return {
    json: {
      ...j,
      ...result,
      needs_llm,
    },
  };
});

const MAGNIX_LLM_DEFAULTS = {"classify":"deepseek","editorial_brief":"deepseek","outreach":"deepseek","video_draft":"deepseek","carousel_draft":"deepseek","content_draft":"anthropic","content_draft_general":"deepseek","content_qa":"anthropic","housex_article":"anthropic"};

function hasLlmKey(raw) {
  return String(raw || '').trim().length > 12;
}

function envProvider(taskId) {
  const key = `MAGNIX_LLM_${String(taskId || '')
    .toUpperCase()
    .replace(/[^A-Z0-9]/g, '_')}_PROVIDER`;
  const v = String($env[key] || '').trim().toLowerCase();
  if (v === 'deepseek' || v === 'anthropic') return v;
  return null;
}

function resolveProvider(taskId) {
  return envProvider(taskId) || MAGNIX_LLM_DEFAULTS[taskId] || 'deepseek';
}

function hasProvider(provider) {
  if (provider === 'anthropic') return hasLlmKey($env.ANTHROPIC_API_KEY);
  return hasLlmKey($env.DEEPSEEK_API_KEY);
}

function anthropicModelForTask(taskId) {
  if (taskId === 'classify') {
    return $env.ANTHROPIC_CLASSIFY_MODEL || 'claude-haiku-4-5-20251001';
  }
  if (taskId === 'video_draft') {
    return $env.ANTHROPIC_VIDEO_MODEL || $env.ANTHROPIC_DRAFT_MODEL || 'claude-sonnet-4-6';
  }
  return $env.ANTHROPIC_DRAFT_MODEL || $env.ANTHROPIC_MODEL || 'claude-sonnet-4-6';
}

async function callDeepSeekLlm(ctx, opts) {
  const {
    system,
    userPayload,
    temperature = 0.35,
    maxTokens = 4096,
    jsonMode = true,
  } = opts;
  return ctx.helpers.httpRequest({
    method: 'POST',
    url: $env.DEEPSEEK_API_URL || 'https://api.deepseek.com/chat/completions',
    headers: {
      Authorization: `Bearer ${$env.DEEPSEEK_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: {
      model: $env.DEEPSEEK_MODEL || 'deepseek-chat',
      temperature,
      max_tokens: maxTokens,
      ...(jsonMode ? { response_format: { type: 'json_object' } } : {}),
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: userPayload },
      ],
    },
    json: true,
  });
}

async function callAnthropicLlm(ctx, opts) {
  const {
    system,
    userPayload,
    temperature = 0.35,
    maxTokens = 4096,
    taskId = 'content_draft',
  } = opts;
  return ctx.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': $env.ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01',
      'Content-Type': 'application/json',
    },
    body: {
      model: anthropicModelForTask(taskId),
      max_tokens: maxTokens,
      temperature,
      system,
      messages: [{ role: 'user', content: userPayload }],
    },
    json: true,
  });
}

async function invokeMagnixLlm(ctx, taskId, opts) {
  const primary = resolveProvider(taskId);
  const fallback = primary === 'deepseek' ? 'anthropic' : 'deepseek';
  const errors = [];

  for (const provider of [primary, fallback]) {
    if (!hasProvider(provider)) continue;
    try {
      if (provider === 'deepseek') {
        return await callDeepSeekLlm(ctx, opts);
      }
      return await callAnthropicLlm(ctx, { ...opts, taskId });
    } catch (e) {
      errors.push(`${provider}: ${e.message}`);
    }
  }

  if (!hasProvider('deepseek') && !hasProvider('anthropic')) {
    throw new Error('Thiếu DEEPSEEK_API_KEY hoặc ANTHROPIC_API_KEY trên n8n env');
  }
  throw new Error(errors.join(' | ') || 'LLM providers failed');
}

const row = $('Loop Pending Rows').item?.json || $input.first().json;

const system = `Bạn là bộ phận phân loại Magnix (BĐS/tài chính VN).
[/focus] [/silent] Chỉ trả JSON hợp lệ, không markdown:
{"segment":"noxh_income|valuation|sme_credit|general_inbound|unclassified","score":0-100,"interest_key":"snake_case"}
Score: 80+ pain rõ; 60-79 warm; 40-59 mơ hồ; <40 cold/spam`;

let metaObj = {};
try {
  metaObj = row.meta ? JSON.parse(row.meta) : {};
} catch {
  metaObj = {};
}

const userPayload = JSON.stringify({
  post_id: row.post_id,
  platform: row.platform,
  text: String(row.text || '').slice(0, 4000),
  meta: metaObj,
});

try {
  const res = await invokeMagnixLlm(this, 'classify', {
    system,
    userPayload,
    temperature: 0.2,
    maxTokens: 256,
    jsonMode: true,
  });
  return [{ json: res }];
} catch (e) {
  return [{ json: { error: true, message: e.message } }];
}

const SEGMENTS = new Set([
  'noxh_income', 'valuation', 'sme_credit', 'general_inbound', 'unclassified',
]);

function extractJsonString(raw) {
  if (raw == null) throw new Error('EMPTY_LLM_OUTPUT');
  const s = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const fenced = s.match(/```(?:json)?\s*([\s\S]*?)```/i);
  return (fenced ? fenced[1] : s).trim();
}

function validateClassify(obj) {
  if (!SEGMENTS.has(obj.segment)) throw new Error('INVALID_SEGMENT');
  const score = Number(obj.score);
  if (!Number.isFinite(score) || score < 0 || score > 100) throw new Error('INVALID_SCORE');
  if (typeof obj.interest_key !== 'string' || !obj.interest_key) throw new Error('INVALID_INTEREST_KEY');
  return { segment: obj.segment, score, interest_key: obj.interest_key };
}

const res = $input.first().json;
const raw =
  res.choices?.[0]?.message?.content ??
  res.content?.[0]?.text ??
  res.message?.content ??
  res.text ??
  res;

try {
  const parsed = JSON.parse(extractJsonString(raw));
  const classify = validateClassify(parsed);
  return [{ json: { ok: true, classify, classify_method: 'llm', parse_error: null } }];
} catch (e) {
  return [{
    json: {
      ok: false,
      classify: null,
      classify_method: 'llm',
      parse_error: e.message,
      raw_preview: String(raw).slice(0, 200),
    },
  }];
}

const j = $input.first().json;
return [{
  json: {
    ok: true,
    classify: {
      segment: j.segment,
      score: j.score,
      interest_key: j.interest_key || j.segment,
    },
    classify_method: 'regex',
  },
}];

function extractQuestion(text) {
  const t = String(text || '').trim();
  if (!t) return [];
  const parts = t.split(/[?？]/).map((s) => s.trim()).filter(Boolean);
  if (parts.length > 1) {
    return parts.slice(0, -1).map((p) => `${p}?`.slice(0, 300)).slice(0, 3);
  }
  if (/[?？]/.test(t)) return [t.slice(0, 300)];
  return [];
}

function buildIntakeStubFromRow(row) {
  const text = String(row.text || '').trim();
  const segment = String(row.segment || 'general_inbound').trim().toLowerCase();
  const score = Number(row.score || 0);
  const platform = String(row.platform || 'tiktok').trim().toLowerCase();
  const questions = extractQuestion(text);
  const summary = text.slice(0, 500);

  return {
    intake_version: 1,
    verdict: score >= 70 ? 'qualified' : score >= 40 ? 'maybe' : 'reject',
    score,
    reject_reason: null,
    summary,
    conversation: {
      surface_topic: summary.slice(0, 200),
      explicit_questions: questions.length ? questions : [summary.slice(0, 120)],
      implicit_fears: [],
      misconceptions: [],
      journey_stage: 'consideration',
      audience_voice: text.slice(0, 300),
    },
    content_signals: {
      pain_intensity: Math.min(100, Math.max(0, score)),
      discussion_heat: score >= 75 ? 'high' : 'medium',
      inbound_potential: score >= 70 ? 'medium' : 'low',
      segment_hint: segment,
      evidence_quotes: text ? [text.slice(0, 120)] : [],
      single_insight_clip: true,
      hook_candidate: text.slice(0, 80),
      cta_keyword_hint: segment === 'noxh_income' ? 'NOXH' : 'CHECKLIST',
    },
    compliance_flags: [],
    _stub: true,
    _stub_source: String(row.intake_stub_source || row.source || 'classified_row'),
    _stub_platform: platform,
    _stub_normalized_key: String(row.normalized_key || ''),
  };
}

function ensureIntakeV1(row, meta) {
  if (meta?.intake_v1 && typeof meta.intake_v1 === 'object') {
    return { meta, intake_v1: meta.intake_v1, stubbed: false };
  }
  const intake_v1 = buildIntakeStubFromRow(row);
  const next = { ...meta, intake_v1, intake_stub_at: new Date().toISOString() };
  return { meta: next, intake_v1, stubbed: true };
}

const source = $('Loop Pending Rows').item?.json || $input.first().json;
const wrap = $input.first().json;

if (!wrap.ok || !wrap.classify) {
  return [{
    json: {
      ok: false,
      error: 'MERGE_SKIP',
      sheet_row: source.sheet_row,
      parse_error: wrap.parse_error,
    },
  }];
}

const { segment, score, interest_key } = wrap.classify;
const method = wrap.classify_method || 'llm';

let status = 'classified';
let claude_verdict = 'qualified';

if (segment === 'unclassified' || score < 40) {
  status = 'raw';
  claude_verdict = 'reject';
} else if (score < 60) {
  status = 'review';
  claude_verdict = 'maybe';
} else if (score < 70) {
  claude_verdict = 'maybe';
}

let metaBase = {};
try {
  if (source.meta) metaBase = typeof source.meta === 'string' ? JSON.parse(source.meta) : source.meta;
} catch {
  metaBase = {};
}

const intakeRow = {
  text: source.text,
  segment,
  score,
  platform: source.platform,
  normalized_key: source.normalized_key,
  source: source.source,
  intake_stub_source: 'agent2_classify',
};
const ensured = ensureIntakeV1(intakeRow, metaBase);
metaBase = ensured.meta;
if (ensured.stubbed) metaBase.intake_v1_from = 'stub_agent2';
else if (!metaBase.intake_v1_from) metaBase.intake_v1_from = 'agent1_or_prior';

const meta = JSON.stringify({
  ...metaBase,
  classify_method: method,
  classified_at: new Date().toISOString(),
  needs_llm: false,
  agent: 'agent-2',
}).slice(0, 50000);

return [{
  json: {
    ok: true,
    sheet_row: source.sheet_row,
    normalized_key: source.normalized_key,
    captured_at: source.captured_at,
    source: source.source,
    classify_method: method,
    update: {
      segment,
      score,
      interest_key,
      status,
      claude_verdict,
      tags: segment !== 'unclassified' ? segment : 'unclassified',
      meta,
    },
  },
}];

const SHEET_ID = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const TAB = 'content_queue';

const item = $input.first().json;
if (!item.ok || !item.sheet_row || !item.update) {
  return [{ json: { ok: false, error: 'SKIP_SHEET_UPDATE', ...item } }];
}

const u = item.update;
const rowValues = [
  String(u.segment ?? ''),
  Number(u.score ?? 0),
  String(u.claude_verdict ?? ''),
  String(u.interest_key ?? ''),
  String(u.status ?? ''),
  String(item.captured_at ?? $('Loop Pending Rows').item?.json?.captured_at ?? ''),
  String(item.source ?? $('Loop Pending Rows').item?.json?.source ?? ''),
  String(u.tags ?? ''),
  String(u.meta ?? ''),
];

const row = item.sheet_row;
const range = `${TAB}!G${row}:O${row}`;

await this.helpers.httpRequestWithAuthentication.call(this, 'googleApi', {
  method: 'PUT',
  url: `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${encodeURIComponent(range)}?valueInputOption=USER_ENTERED`,
  body: { values: [rowValues] },
  json: true,
});

const data = $getWorkflowStaticData('global');
if (!data.a2_stats) data.a2_stats = { sheet_ok: 0, sheet_fail: 0, llm: 0, regex: 0, parse_fail: 0 };
data.a2_stats.sheet_ok += 1;
if (item.classify_method === 'llm') data.a2_stats.llm += 1;
else data.a2_stats.regex += 1;

return [{
  json: {
    ok: true,
    storage: 'sheet_content_queue',
    sheet_row: row,
    normalized_key: item.normalized_key,
    segment: u.segment,
    score: u.score,
    classify_method: item.classify_method || u.classify_method,
  },
}];

const data = $getWorkflowStaticData('global');
if (!data.a2_stats) data.a2_stats = { sheet_ok: 0, sheet_fail: 0, llm: 0, regex: 0, parse_fail: 0 };
data.a2_stats.parse_fail += 1;

return [{ json: { ok: false, dead_letter: true, ...$input.first().json } }];

const data = $getWorkflowStaticData('global');
const stats = data.a2_stats || {};
let hint = null;
if ((stats.sheet_ok || 0) === 0) {
  hint = 'Không cập nhật dòng nào — hết pending hoặc lỗi credential googleApi trên Sheet Update Row';
} else if ((stats.parse_fail || 0) > 0) {
  hint = 'Có parse_fail — kiểm tra DEEPSEEK/ANTHROPIC key hoặc output LLM';
}
return [{ json: {
  ok: true,
  workflow: 'content-classify',
  stats,
  hint,
  batch_size: 200,
  finished_at: new Date().toISOString(),
}}];
